import{_ as o,o as a,c as t,ag as i}from"./chunks/framework.BDReElpY.js";const m=JSON.parse('{"title":"Operator Overloading","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/operator_overloading.md","filePath":"archive/reference/operator_overloading.md"}'),l={name:"archive/reference/operator_overloading.md"};function n(r,e,s,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="operator-overloading" tabindex="-1">Operator Overloading <a class="header-anchor" href="#operator-overloading" aria-label="Permalink to &quot;Operator Overloading&quot;">​</a></h1><p><strong>Version:</strong> 0.2.0<br><strong>Date:</strong> November 12, 2025<br><strong>Status:</strong> Syntax Ready (Codegen Pending)</p><hr><h2 id="🎯-core-principles" tabindex="-1">🎯 Core Principles <a class="header-anchor" href="#🎯-core-principles" aria-label="Permalink to &quot;🎯 Core Principles&quot;">​</a></h2><ol><li><strong>Contract-based</strong>: Operators MUST be declared in a contract first.</li><li><strong><code>op</code> prefix mandatory</strong>: All operator methods use <code>op+</code>, <code>op-</code>, <code>op*</code>, etc.</li><li><strong>Multiple overloads</strong>: One contract can define multiple operator overloads with different parameter types.</li><li><strong>Explicit implementation</strong>: No automatic derivation — the implementing type explicitly defines its operator methods.</li></ol><hr><h2 id="📋-overview" tabindex="-1">📋 Overview <a class="header-anchor" href="#📋-overview" aria-label="Permalink to &quot;📋 Overview&quot;">​</a></h2><p>Operator overloading in Vex is implemented as a capability provided through contracts. Contracts declare <code>op</code> methods and implementing types (typically <code>struct</code>s) provide concrete methods to support operator syntax.</p><p>The operator names follow the form <code>op&lt;token&gt;</code>, for example <code>op+</code>, <code>op-</code>, <code>op==</code>, as method names in contract declarations and implementations.</p><p>The compiler resolves an operator expression <code>a + b</code> by:</p><ol><li>Checking whether <code>a</code>&#39;s type implements the contract that defines <code>op+</code>.</li><li>Looking up the overload that best matches the right-hand side argument (<code>b</code>), including builtin primitive rules and <code>Self</code> substitutions.</li><li>Compiling a direct call to the corresponding method (<code>a.op+(b)</code>).</li></ol><hr><h2 id="syntax-contract-declarations" tabindex="-1">Syntax: Contract Declarations <a class="header-anchor" href="#syntax-contract-declarations" aria-label="Permalink to &quot;Syntax: Contract Declarations&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>contract $Add {</span></span>
<span class="line"><span>    op+(rhs: Self): Self;                    // Same type add</span></span>
<span class="line"><span>    op+(rhs: i32): Self;                     // Overload with i32</span></span>
<span class="line"><span>    op+(rhs: f64): Self;                     // Overload with f64</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Rules:</p><ul><li>Contract name describes the capability (<code>Add</code>, <code>Mul</code>, <code>Eq</code>).</li><li>All operator methods must use <code>op</code> prefix.</li><li>Overloads are allowed as distinct method signatures.</li><li>Return type is explicit and independent per overload.</li></ul><hr><h2 id="syntax-implementation" tabindex="-1">Syntax: Implementation <a class="header-anchor" href="#syntax-implementation" aria-label="Permalink to &quot;Syntax: Implementation&quot;">​</a></h2><p>Vex supports both <strong>Inline</strong> and <strong>External</strong> implementation.</p><h3 id="inline-implementation-implicit-self" tabindex="-1">Inline Implementation (Implicit Self) <a class="header-anchor" href="#inline-implementation-implicit-self" aria-label="Permalink to &quot;Inline Implementation (Implicit Self)&quot;">​</a></h3><p>When defined inside the struct, <code>self</code> is implicit.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct Vec2 impl Add {</span></span>
<span class="line"><span>    x: f32,</span></span>
<span class="line"><span>    y: f32,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // Inline: &#39;self&#39; is implicit</span></span>
<span class="line"><span>    fn op+(other: Vec2): Vec2 {</span></span>
<span class="line"><span>        return Vec2 { x: self.x + other.x, y: self.y + other.y };</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="external-implementation-explicit-self" tabindex="-1">External Implementation (Explicit Self) <a class="header-anchor" href="#external-implementation-explicit-self" aria-label="Permalink to &quot;External Implementation (Explicit Self)&quot;">​</a></h3><p>Use this for cleaner separation of data and behavior.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn (self: Vec2) op+(other: Vec2): Vec2 {</span></span>
<span class="line"><span>    return Vec2 { x: self.x + other.x, y: self.y + other.y };</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Rules:</p><ul><li>Struct must declare <code>impl ContractName</code>.</li><li>Inline methods have implicit <code>self</code>.</li><li>External methods use receiver syntax <code>(self: Type)</code>.</li></ul><hr><h2 id="resolution-semantics" tabindex="-1">Resolution &amp; Semantics <a class="header-anchor" href="#resolution-semantics" aria-label="Permalink to &quot;Resolution &amp; Semantics&quot;">​</a></h2><ul><li>Operator expression <code>a + b</code> resolves to <code>a.op+(b)</code> if <code>a</code>&#39;s type implements the contract with a matching signature.</li><li>Matching uses compile-time types; no implicit conversions except for the builtin <code>extends</code> contract mapping for primitives.</li><li>If no match is found on the left-hand type, the compiler attempts to check for <code>coerce</code> rules and builtin operators (primitives), and finally raises an error.</li></ul><hr><h2 id="overloadable-operators" tabindex="-1">Overloadable Operators <a class="header-anchor" href="#overloadable-operators" aria-label="Permalink to &quot;Overloadable Operators&quot;">​</a></h2><p>The following operators can be overloaded by defining the corresponding method on the type.</p><h3 id="arithmetic" tabindex="-1">Arithmetic <a class="header-anchor" href="#arithmetic" aria-label="Permalink to &quot;Arithmetic&quot;">​</a></h3><ul><li><code>+</code> : <code>fn op+(self: &amp;Self, other: Other): Result</code></li><li><code>-</code> : <code>fn op-(self: &amp;Self, other: Other): Result</code></li><li><code>*</code> : <code>fn op*(self: &amp;Self, other: Other): Result</code></li><li><code>/</code> : <code>fn op/(self: &amp;Self, other: Other): Result</code></li><li><code>%</code> : <code>fn op%(self: &amp;Self, other: Other): Result</code></li></ul><h3 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h3><ul><li><code>==</code> : <code>fn op==(self: &amp;Self, other: Other): bool</code></li><li><code>!=</code> : <code>fn op!=(self: &amp;Self, other: Other): bool</code></li><li><code>&lt;</code> : <code>fn op&lt;(self: &amp;Self, other: Other): bool</code></li><li><code>&lt;=</code> : <code>fn op&lt;=(self: &amp;Self, other: Other): bool</code></li><li><code>&gt;</code> : <code>fn op&gt;(self: &amp;Self, other: Other): bool</code></li><li><code>&gt;=</code> : <code>fn op&gt;=(self: &amp;Self, other: Other): bool</code></li></ul><h3 id="bitwise" tabindex="-1">Bitwise <a class="header-anchor" href="#bitwise" aria-label="Permalink to &quot;Bitwise&quot;">​</a></h3><ul><li><code>&amp;</code> : <code>fn op&amp;(self: &amp;Self, other: Other): Result</code></li><li><code>|</code> : <code>fn op|(self: &amp;Self, other: Other): Result</code></li><li><code>^</code> : <code>fn op^(self: &amp;Self, other: Other): Result</code></li><li><code>~</code> : <code>fn op~(self: &amp;Self): Result</code> (Unary NOT)</li><li><code>&lt;&lt;</code> : <code>fn op&lt;&lt;(self: &amp;Self, shift: u32): Result</code></li><li><code>&gt;&gt;</code> : <code>fn op&gt;&gt;(self: &amp;Self, shift: u32): Result</code></li><li><code>&lt;&lt;&lt;</code> : <code>fn op&lt;&lt;&lt;(self: &amp;Self, shift: u32): Result</code> (Rotate Left)</li><li><code>&gt;&gt;&gt;</code> : <code>fn op&gt;&gt;&gt;(self: &amp;Self, shift: u32): Result</code> (Rotate Right)</li></ul><h3 id="increment-decrement" tabindex="-1">Increment/Decrement <a class="header-anchor" href="#increment-decrement" aria-label="Permalink to &quot;Increment/Decrement&quot;">​</a></h3><ul><li><code>++</code> : <code>fn op++(self: &amp;Self!)</code> (Postfix)</li><li><code>--</code> : <code>fn op--(self: &amp;Self!)</code> (Postfix)</li></ul><h3 id="indexing" tabindex="-1">Indexing <a class="header-anchor" href="#indexing" aria-label="Permalink to &quot;Indexing&quot;">​</a></h3><ul><li><code>[]</code> : <code>fn op[](self: &amp;Self, index: Index): &amp;Output</code></li><li><code>[]=</code> : <code>fn op[]=(self: &amp;Self!, index: Index, value: Value)</code></li><li><code>[..]</code> : <code>fn op[..](self: &amp;Self, range: Range): &amp;Output</code></li><li><code>[..]=</code> : <code>fn op[..]=(self: &amp;Self!, range: Range, value: Value)</code></li></ul><h3 id="special" tabindex="-1">Special <a class="header-anchor" href="#special" aria-label="Permalink to &quot;Special&quot;">​</a></h3><ul><li><code>?</code> : <code>fn op?(self: &amp;Self): bool</code> (Truthiness check)</li><li><code>!</code> : <code>fn op!(self: &amp;Self): Result</code> (Logical qualifiers)</li></ul><hr><h2 id="mutability-side-effects" tabindex="-1">Mutability &amp; Side Effects <a class="header-anchor" href="#mutability-side-effects" aria-label="Permalink to &quot;Mutability &amp; Side Effects&quot;">​</a></h2><ul><li>Operators that are mutation semantics (like <code>op+=</code>) should be defined to mutate <code>self</code> with signature including <code>!</code> where the contract or implementation requires a mutable receiver.</li><li>The <code>!</code> syntax in method signatures indicates the method requires a mutable reference for <code>self</code>.</li></ul><hr><h2 id="builtin-primitives-extends" tabindex="-1">Builtin Primitives &amp; <code>extends</code> <a class="header-anchor" href="#builtin-primitives-extends" aria-label="Permalink to &quot;Builtin Primitives &amp; \`extends\`&quot;">​</a></h2><ul><li>The standard library declares <code>extends</code> for primitive types and builtin contracts to provide default operator support. These are specified in <code>stdlib/core/builtin_contracts.vx</code> and related files.</li><li><code>extends</code> indicates a special compiler-provided mapping for primitives and is not the same as a user <code>impl</code> for user-defined types.</li></ul><hr><h2 id="auto-generation-default-implementations" tabindex="-1">Auto-Generation &amp; Default Implementations <a class="header-anchor" href="#auto-generation-default-implementations" aria-label="Permalink to &quot;Auto-Generation &amp; Default Implementations&quot;">​</a></h2><ul><li>The compiler may auto-generate comparisons (<code>op!=</code> from <code>op==</code>) when semantically correct.</li><li>Default contract methods that have body can be used to offer generic operator compositions (e.g., <code>op!=</code> defaulting to <code>!op==</code>).</li></ul><hr><h2 id="diagnostics-errors" tabindex="-1">Diagnostics &amp; Errors <a class="header-anchor" href="#diagnostics-errors" aria-label="Permalink to &quot;Diagnostics &amp; Errors&quot;">​</a></h2><ul><li>Type mismatch in operator operands or return type mismatches result in compile errors.</li><li>When multiple overloads are applicable, the compiler uses exact type match precedence, then consider generic matches and coercions.</li></ul><hr><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><p>See <code>examples/</code> for several samples and tests:</p><ul><li><code>examples/test_operator_overloading.vx</code></li><li><code>examples/test_operator_unary_neg.vx</code></li><li><code>examples/operator/05_all_operators.vx</code></li><li><code>examples/PROPOSAL_operator_syntax.vx</code></li></ul><hr><h2 id="implementation-notes-compiler" tabindex="-1">Implementation Notes (Compiler) <a class="header-anchor" href="#implementation-notes-compiler" aria-label="Permalink to &quot;Implementation Notes (Compiler)&quot;">​</a></h2><ul><li>Parser: Operator method names are parsed as <code>op</code> token followed by punctuation (e.g., <code>+</code>, <code>-</code>, <code>==</code>).</li><li>Resolution: Compiler looks up <code>impl</code> for contract, ensuring correct arity and parameter types.</li><li>Codegen: For user-defined types, the compiler emits calls to the method implementation; for primitives, it emits optimized IR.</li></ul><hr><h2 id="security-safety-considerations" tabindex="-1">Security &amp; Safety Considerations <a class="header-anchor" href="#security-safety-considerations" aria-label="Permalink to &quot;Security &amp; Safety Considerations&quot;">​</a></h2><ul><li>Overloading assignment operators like <code>op=</code> is either forbidden or strongly discouraged due to move/copy semantics that can easily introduce surprising behavior.</li><li>Implementations must be careful around mutability to avoid aliasing and data races in concurrent code.</li></ul><hr><h2 id="future-work-open-questions" tabindex="-1">Future Work / Open Questions <a class="header-anchor" href="#future-work-open-questions" aria-label="Permalink to &quot;Future Work / Open Questions&quot;">​</a></h2><ul><li>Cross-type operator inference rules and conversions.</li><li>Automatic generation of <code>op!=</code> vs <code>op==</code> symmetries for compound or complex types.</li><li>Partial ordering inference for <code>Ord</code>.</li></ul><hr><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li>v0.2.0: Specification draft consolidating operator overloading phases and builtin contracts.</li></ul><hr><blockquote><p>See also: <code>OPERATOR_OVERLOADING_SPEC.md</code> at repository root for the original in-depth draft and additional examples.</p></blockquote>`,75)])])}const u=o(l,[["render",n]]);export{m as __pageData,u as default};
